46	/// Leading `SYS_EXIT` calls to trace explicitly — terminations are
47	/// once-per-boot events in the 4.5 demo, invisible to the modulo-100 `[ksys]`
48	/// sampler (same reasoning as `do_schedule::SCHED_TRACE_HEAD`).
49	const EXIT_TRACE_HEAD: u64 = 6;
50	static EXIT_COUNT: AtomicU64 = AtomicU64::new(0);
51	
52	/// `SYS_EXIT` — permanently stop the target and detach it from IPC.
53	pub(super) fn do_exit(
54	    proc_table: &mut [Proc; N_PROC_SLOTS],
55	    caller_nr: ProcNr,
56	    msg: &mut Message,
57	) -> i32 {
58	    let target_e: Endpoint = read_i32(msg, 0);
59	
60	    let target_nr = if target_e == SELF {
61	        caller_nr
62	    } else {
63	        endpoint_proc(target_e)
64	    };
65	    let Some(target_idx) = proc_index(target_nr) else {
66	        return EINVAL;
67	    };
