1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! Endpoints and generation-aware proc-number encoding.
4	//!
5	//! An `Endpoint` is the kernel's name for a process. It encodes both the
6	//! process-table slot (`ProcNr`) and a generation counter (`GenNr`) so that
7	//! a slot reuse after a process exit produces a distinct endpoint. This
8	//! catches stale-endpoint bugs in user-space code.
9	//!
10	//! Mirrors MINIX 3 `include/minix/type.h` (`typedef int endpoint_t`) and
11	//! `include/minix/endpoint.h` (the `_ENDPOINT(g, n)` / `_ENDPOINT_P(e)` /
12	//! `_ENDPOINT_G(e)` macros), with one deliberate ABI deviation: minix.rs
13	//! uses sign-extension of the low `ENDPOINT_GEN_SHIFT` bits to recover
14	//! negative task slots, rather than MINIX 3's `MAX_NR_TASKS` offset-bias
15	//! trick. The consequence is that `make_endpoint(0, p) != p` for negative
16	//! `p` — use `boot_endpoint(p)` explicitly when constructing an endpoint
17	//! from a kernel-task `ProcNr` constant like `SYSTEM`.
18	
19	use core::fmt;
20	
21	/// Kernel-assigned identifier for a process; encodes generation + proc_nr.
22	///
23	/// Stays an `i32` alias because it is wire-format: passed through registers
24	/// on the IPC trap and stored in `Message::m_source`. The strongly-typed
25	/// process and privilege indices live in [`ProcNr`] and [`PrivId`].
26	pub type Endpoint = i32;
27	
28	/// Generation counter — bumped when a process slot is reused.
29	pub type GenNr = i32;
30	
31	/// Index into the process table. Task slots are negative (`SYSTEM = -2`, …);
32	/// user-process slots are non-negative.
33	///
34	/// Wraps an `i32` rather than aliasing it so the compiler can distinguish a
35	/// proc-table index from an [`Endpoint`] or a raw register value. Use
36	/// [`ProcNr::new`] for construction and [`ProcNr::get`] when an `i32` is
37	/// needed (e.g. bit-ops or casts to `usize`).
38	#[repr(transparent)]
39	#[derive(Copy, Clone, Debug, PartialEq, Eq, PartialOrd, Ord, Hash)]
40	pub struct ProcNr(i32);
41	
42	impl ProcNr {
43	    pub const fn new(n: i32) -> Self {
44	        Self(n)
45	    }
46	    pub const fn get(self) -> i32 {
47	        self.0
48	    }
49	    pub const fn is_task(self) -> bool {
50	        self.0 < 0
51	    }
52	}
53	
54	impl fmt::Display for ProcNr {
55	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
56	        write!(f, "{}", self.0)
57	    }
58	}
59	
60	/// Index into the privilege table. Sized to cover `NR_SYS_PROCS` slots; each
61	/// system (privileged) process has its own slot, and all non-system user
62	/// processes share one. Mirrors MINIX 3 `priv.h`'s `s_id` field.
63	#[repr(transparent)]
64	#[derive(Copy, Clone, Debug, PartialEq, Eq, PartialOrd, Ord, Hash)]
65	pub struct PrivId(u16);
66	
67	impl PrivId {
68	    pub const fn new(n: u16) -> Self {
69	        Self(n)
70	    }
71	    pub const fn get(self) -> u16 {
72	        self.0
73	    }
74	    pub const fn as_usize(self) -> usize {
75	        self.0 as usize
76	    }
77	}
78	
79	impl fmt::Display for PrivId {
80	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
81	        write!(f, "{}", self.0)
82	    }
83	}
84	
85	/// MINIX 3 spelling of [`PrivId`]; kept as a type alias for code that reads
86	/// closer to the reference (e.g. translating `sys_id_t s_id`). The two names
87	/// are interchangeable.
88	pub type SysId = PrivId;
89	
90	/// Width of the proc-number field within an endpoint, in bits. Generation
91	/// occupies the bits above this.
92	pub const ENDPOINT_GEN_SHIFT: i32 = 15;
93	
94	/// Mask covering the proc-number field of an endpoint.
95	pub const ENDPOINT_PROC_MASK: i32 = (1 << ENDPOINT_GEN_SHIFT) - 1;
96	
97	/// Highest positive proc-number representable at generation zero (one less
98	/// than the sign-bit boundary of the proc field). Sentinel endpoints live
99	/// just below this so they decode to gen 0 with proc-numbers well outside
100	/// any plausible `NR_PROCS`. Mirrors MINIX 3's `_ENDPOINT_SLOT_TOP`.
101	pub const ENDPOINT_SLOT_TOP: ProcNr = ProcNr::new((1 << (ENDPOINT_GEN_SHIFT - 1)) - 1);
