2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! `RECEIVE` — synchronous receive.
4	//!
5	//! Translation of MINIX 3 `kernel/proc.c:977 mini_receive()`. Searches in
6	//! order: pending notifications (synthesized on the fly from the caller's
7	//! `priv.notify_pending` bitmap), then queued senders in `caller_q`. If
8	//! nothing matches, the caller blocks with `RTS_RECEIVING` and records
9	//! the source filter and user-buffer VA so a later [`mini_send`] can
10	//! deposit the message and unblock us.
11	
12	use core::sync::atomic::Ordering;
13	
14	use minixrs_kernel_shared::ProcNr;
15	use minixrs_kernel_shared::com::NR_SYS_PROCS;
16	use minixrs_kernel_shared::endpoint::{ANY, Endpoint};
17	use minixrs_kernel_shared::error::{EBADSRCDST, ELOCKED, ENOTREADY, OK};
18	use minixrs_kernel_shared::ipc_const::RECEIVE;
19	
20	use crate::ipc::deadlock::deadlock_check;
21	use crate::ipc::notify::build_notify_message;
22	use crate::proc::flags::{MF_DELIVERMSG, MF_REPLY_PEND, RTS_RECEIVING, RTS_SENDING};
23	use crate::proc::priv_struct::IPC_MAP_CHUNKS;
24	use crate::proc::table::{N_PROC_SLOTS, proc_index};
25	use crate::proc::{Priv, Proc, sched};
26	
27	/// Blocking discipline for [`mini_receive`].
28	#[derive(Copy, Clone, Eq, PartialEq, Debug)]
29	pub enum RecvFlags {
30	    /// `RECEIVE` — block if no matching message is queued.
31	    Blocking,
32	    /// Non-blocking (no IPC primitive exposes this today, but the dispatch
33	    /// path passes it from the `RECEIVE` half of a SENDREC; symmetric to
34	    /// [`super::send::SendFlags::NonBlocking`]).
35	    #[allow(dead_code)]
36	    NonBlocking,
37	}
38	
39	/// `RECEIVE` primitive.
40	pub fn mini_receive(
41	    proc_table: &mut [Proc; N_PROC_SLOTS],
42	    priv_table: &mut [Priv; NR_SYS_PROCS],
43	    caller_nr: ProcNr,
44	    src_e: Endpoint,
45	    user_msg_va: u64,
46	    flags: RecvFlags,
47	) -> i32 {
48	    let Some(caller_idx) = proc_index(caller_nr) else {
49	        return EBADSRCDST;
50	    };
51	
52	    // Record buffer VA up-front. Even if we block here, a later deferred
53	    // SEND will find this and deposit the message at the right place when
54	    // the flush path runs.
55	    proc_table[caller_idx].deliver_msg_vir = user_msg_va;
56	
57	    // SENDREC mid-flight: SEND half blocked, RECEIVE half just kicked in.
58	    // Skip pending-message checks and proceed straight to "block on
59	    // receive". MINIX 3 proc.c:1010.
60	    let caller_rts = proc_table[caller_idx].rts_flags.load(Ordering::Relaxed);
61	    let in_mid_sendrec = caller_rts & RTS_SENDING != 0;
62	
63	    if !in_mid_sendrec {
64	        // 1. Pending notification?
65	        if let Some(sender_e) = take_pending_notification(proc_table, priv_table, caller_idx, src_e)
66	        {
67	            let caller = &mut proc_table[caller_idx];
68	            build_notify_message(caller, sender_e);
69	            caller.misc_flags |= MF_DELIVERMSG;
70	            return OK;
71	        }
72	
73	        // 2. (Skip pending async — `mini_senda` is an ENOSYS stub.)
74	
75	        // 3. Walk caller_q for a sender matching src_e (or ANY).
76	        if let Some(matched) = walk_caller_q(proc_table, caller_idx, src_e) {
77	            return matched;
78	        }
79	    }
80	
81	    // Nothing to deliver.
82	    if flags == RecvFlags::NonBlocking {
83	        return ENOTREADY;
84	    }
85	
86	    if deadlock_check(&*proc_table, RECEIVE, caller_nr, src_e) {
87	        return ELOCKED;
88	    }
89	
90	    let caller = &mut proc_table[caller_idx];
91	    caller.getfrom_e = src_e;
92	    // SAFETY: single-threaded SVC invariant; no other borrow into
93	    // `proc_table` is live.
94	    unsafe { sched::rts_set(caller, RTS_RECEIVING) };
95	    OK
96	}
97	
98	/// Look for the first pending notification matching `src_e` (or any, if
99	/// `src_e == ANY`) in `caller`'s `notify_pending` bitmap. Returns the
100	/// sender's endpoint and clears the bit on success.
101	fn take_pending_notification(
102	    proc_table: &[Proc; N_PROC_SLOTS],
103	    priv_table: &mut [Priv; NR_SYS_PROCS],
104	    caller_idx: usize,
105	    src_e: Endpoint,
106	) -> Option<Endpoint> {
107	    let Some(caller_priv_id) = proc_table[caller_idx].priv_id else {
108	        return None;
109	    };
110	    let caller_priv_idx = caller_priv_id.as_usize();
111	
112	    // Snapshot the caller's notify_pending bitmap so the lookup loop can
113	    // read other priv_table slots without holding a mutable borrow.
114	    let pending_snapshot: [u32; IPC_MAP_CHUNKS] = priv_table[caller_priv_idx].notify_pending;
115	
116	    // TODO(slice 2.6+): when src_e != ANY, resolve priv_id directly
117	    // (endpoint → proc_index → priv_id) and test that single bit, rather
118	    // than scanning the whole bitmap. Current map is 64 bits so the walk
119	    // is fine, but cost grows with NR_SYS_PROCS.
120	    for chunk_idx in 0..pending_snapshot.len() {
121	        let mut chunk = pending_snapshot[chunk_idx];
122	        while chunk != 0 {
123	            let bit = chunk.trailing_zeros() as usize;
124	            let sender_priv_idx = chunk_idx * 32 + bit;
125	            if sender_priv_idx < NR_SYS_PROCS {
126	                if let Some(sender_nr) = priv_table[sender_priv_idx].proc_nr {
127	                    if let Some(sender_idx) = proc_index(sender_nr) {
128	                        let sender_e = proc_table[sender_idx].endpoint;
129	                        if src_e == ANY || src_e == sender_e {
130	                            // Clear bit and return.
131	                            priv_table[caller_priv_idx].notify_pending[chunk_idx] &= !(1u32 << bit);
132	                            return Some(sender_e);
133	                        }
134	                    }
135	                }
136	            }
137	            chunk &= chunk - 1; // pop lowest set bit and try next
138	        }
139	    }
140	    None
141	}
142	
143	/// Walk `caller_q` rooted at `proc_table[caller_idx]` for the first sender
144	/// matching `src_e` (or any, if `src_e == ANY`). On match, deliver the
145	/// sender's `send_msg` into the caller's `deliver_msg`, set `MF_DELIVERMSG`,
146	/// clear `MF_REPLY_PEND` (SENDREC completion), unblock the sender, splice
147	/// it out of the queue, and return `Some(OK)`. Returns `None` if nothing
148	/// matches.
149	fn walk_caller_q(
150	    proc_table: &mut [Proc; N_PROC_SLOTS],
151	    caller_idx: usize,
152	    src_e: Endpoint,
153	) -> Option<i32> {
154	    let mut prev: Option<usize> = None;
155	    let mut cur = proc_table[caller_idx].caller_q;
156	
157	    while let Some(sender_nr) = cur {
158	        let sender_idx = proc_index(sender_nr).expect("caller_q entry in range");
159	        let sender_e = proc_table[sender_idx].endpoint;
160	        let next = proc_table[sender_idx].q_link;
161	
162	        if src_e == ANY || src_e == sender_e {
163	            // Deliver: copy the buffered message into the caller's
164	            // deliver_msg (m_source was already stamped by mini_send).
165	            let msg = proc_table[sender_idx].send_msg;
166	            let caller = &mut proc_table[caller_idx];
167	            caller.deliver_msg = msg;
168	            caller.misc_flags |= MF_DELIVERMSG;
169	            caller.misc_flags &= !MF_REPLY_PEND;
170	
171	            // Splice sender out of the queue.
172	            match prev {
173	                None => proc_table[caller_idx].caller_q = next,
174	                Some(p_idx) => proc_table[p_idx].q_link = next,
175	            }
176	            {
177	                let sender = &mut proc_table[sender_idx];
178	                sender.q_link = None;
