                sender.q_link = None;
                // SAFETY: single-threaded SVC invariant.
                unsafe { sched::rts_unset(sender, RTS_SENDING) };
            }
            return Some(OK);
        }

        prev = Some(sender_idx);
        cur = next;
    }
    None
}

