    let target_e: Endpoint = read_i32(msg, 0);
    let signo = read_i32(msg, 4);

    if !(1..NSIG as i32).contains(&signo) {
        return EINVAL;
    }
    let Some(target_idx) = proc_index(endpoint_proc(target_e)) else {
        return EINVAL;
    };
