8	#![allow(dead_code)]
9	
10	//! Per-process aarch64 address space.
11	//!
12	//! Slice 3.1a introduces this API but no proc consumes it yet — the kmain
13	//! smoke test exercises it standalone, and slice 3.1b will swap `userland.rs`
14	//! over so each EL0 stub gets its own [`AddrSpace`] instead of the shared
15	//! static L0/L1/L2/L3 arrays.
16	//!
17	//! The walk follows the same 4 KiB-granule, 4-level, 48-bit-VA layout that
18	//! [`super::mmu`] already documents and verifies on Limine handoff. Intermediate
19	//! tables (L1, L2, L3) are allocated on demand from the frame allocator —
20	//! [`AddrSpace::new`] only allocates the L0 root; each `map_page` walk
21	//! allocates whatever sub-tables are missing.
22	//!
23	//! All page-table writes go through HHDM — we never touch a table via its
24	//! own VA, because at slice-3.1a time the address space isn't activated.
25	//! Slice 3.1b's context switch will install [`AddrSpace::ttbr0_pa`] into
26	//! TTBR0_EL1; until then, AddrSpaces are passive data structures.
27	
28	use crate::arch::aarch64::mmu::{
29	    ATTR_IDX_NORMAL, PAGE_SHIFT, PTE_AF, PTE_AP_RO_EL0, PTE_AP_RW_EL0, PTE_PXN, PTE_SH_INNER,
30	    PTE_TABLE, PTE_UXN, PTE_VALID, PTES_PER_LEVEL, pte_attr_idx,
31	};
32	use crate::mm::{FRAME_SIZE, Frame, alloc_frame, free_frame, phys_to_hhdm};
33	
34	/// User-page permission. Maps onto the aarch64 stage-1 descriptor's AP +
35	/// PXN + UXN bits; kernel callers describe intent here and `prot_attrs()`
36	/// converts to the bit pattern.
37	#[derive(Copy, Clone, Debug)]
38	pub struct Prot {
39	    /// EL0 may write.
40	    pub writable: bool,
41	    /// EL0 may fetch from this page (code).
42	    pub executable: bool,
43	}
44	
45	impl Prot {
46	    pub const RO_CODE: Self = Self {
47	        writable: false,
48	        executable: true,
49	    };
50	    pub const RW_DATA: Self = Self {
51	        writable: true,
52	        executable: false,
53	    };
54	    pub const RO_DATA: Self = Self {
55	        writable: false,
56	        executable: false,
57	    };
58	}
59	
60	fn prot_attrs(prot: Prot) -> u64 {
61	    let ap = if prot.writable {
62	        PTE_AP_RW_EL0
63	    } else {
64	        PTE_AP_RO_EL0
65	    };
66	    let uxn = if prot.executable { 0 } else { PTE_UXN };
67	    PTE_AF | PTE_SH_INNER | ap | PTE_PXN | uxn | pte_attr_idx(ATTR_IDX_NORMAL)
68	}
69	
70	/// Errors from [`AddrSpace`] operations.
71	#[derive(Copy, Clone, Debug, PartialEq, Eq)]
72	pub enum MapError {
73	    /// Frame allocator returned `None`; no physical memory left for an
74	    /// intermediate page table or for the L0 root.
75	    OutOfMemory,
76	    /// `va` is not 4 KiB-aligned.
77	    Misaligned,
78	    /// `va` is outside the 48-bit user-VA window.
79	    OutOfRange,
80	    /// A leaf PTE is already present at `va` and the caller asked for a
81	    /// fresh mapping. Use [`AddrSpace::unmap_page`] to clear first.
82	    AlreadyMapped,
83	}
84	
85	/// One per-process page-table tree, rooted at the L0 frame whose PA goes
86	/// into TTBR0_EL1 on context switch.
87	pub struct AddrSpace {
88	    /// PA of the L0 page-table root. Always frame-aligned.
89	    pub ttbr0_pa: u64,
90	}
91	
92	impl AddrSpace {
93	    /// Build a fresh, empty address space. Allocates one frame for the L0
94	    /// root; intermediate L1/L2/L3 tables come later, on first `map_page`.
95	    pub fn new() -> Result<Self, MapError> {
96	        let l0 = alloc_frame().ok_or(MapError::OutOfMemory)?;
97	        // `alloc_frame` zeroes the frame, so the L0 starts all-invalid.
98	        Ok(Self {
99	            ttbr0_pa: l0.addr(),
100	        })
101	    }
102	
103	    /// Install a single 4 KiB mapping `va → pa` with the given permissions.
104	    ///
105	    /// Intermediate L1/L2/L3 tables are allocated from the frame allocator
106	    /// as needed. Returns `Err(AlreadyMapped)` if `va` already has a leaf
107	    /// PTE (callers must `unmap_page` first to replace).
108	    pub fn map_page(&mut self, va: u64, pa: u64, prot: Prot) -> Result<(), MapError> {
109	        map_page_in(self.ttbr0_pa, va, pa, prot)
110	    }
111	
112	    /// Clear the leaf PTE at `va`. Returns `Some(pa)` if a mapping was
113	    /// present, `None` otherwise. The freed PA is returned to the caller —
114	    /// it's the caller's job to `free_frame` if appropriate (the page
115	    /// might be a CoW share, a device PA, or stale; the address space
116	    /// itself doesn't know).
117	    ///
118	    /// Does not free intermediate L1/L2/L3 tables even if they become
119	    /// empty — that's left to [`Self::destroy`]. Avoiding incremental
120	    /// pruning keeps `unmap_page` O(walk) and matches what real MINIX 3
121	    /// does (lazy pruning at exec/exit time).
122	    pub fn unmap_page(&mut self, va: u64) -> Option<u64> {
123	        unmap_page_in(self.ttbr0_pa, va)
124	    }
125	
126	    /// Walk the page table to find the PA backing `va`, or `None` if `va`
127	    /// is unmapped.
128	    pub fn walk_pt(&self, va: u64) -> Option<u64> {
129	        check_va(va).ok()?;
130	        let l0 = self.ttbr0_pa;
131	        let l1 = next_table(l0, pte_index(va, 0))?;
132	        let l2 = next_table(l1, pte_index(va, 1))?;
133	        let l3 = next_table(l2, pte_index(va, 2))?;
134	        let pte = table_ref(l3)[pte_index(va, 3)];
135	        if pte & PTE_VALID == 0 {
136	            None
137	        } else {
138	            Some(pte & PA_MASK)
139	        }
140	    }
141	
142	    /// Free every intermediate L1/L2/L3 table and the L0 root.
143	    ///
144	    /// Leaf-page frames (the PAs that `map_page` installed) are *not*
145	    /// freed — the address space owns the page-table tree, not the pages
146	    /// it points at. The caller is responsible for tracking and freeing
147	    /// leaf frames before calling this; otherwise they leak. Phase 3.5's
148	    /// VM region tracker is what eventually owns leaf-frame lifetimes.
149	    pub fn destroy(self) {
150	        // Walk the L0 root, recursing into table descriptors. Page
151	        // descriptors (PTE_VALID & PTE_TABLE both set at L3) are leaves
152	        // and left alone; intermediate tables (PTE_VALID & PTE_TABLE at
153	        // L0/L1/L2) get recursed-into then freed.
154	        free_subtree(self.ttbr0_pa, 0);
155	        free_frame(Frame::from_addr(self.ttbr0_pa));
156	    }
157	}
158	
159	// ----- helpers --------------------------------------------------------------
160	
161	/// Install a single 4 KiB mapping `va → pa` into the page-table tree rooted
162	/// at `ttbr0_pa`, allocating intermediate L1/L2/L3 tables on demand.
163	///
164	/// This is the body of [`AddrSpace::map_page`], exposed as a free function
165	/// so the kernel can map into a proc's *live* address space given only the
166	/// `ttbr0_pa` stored on its [`Proc`](crate::proc::Proc) slot — without
167	/// reconstructing an owning [`AddrSpace`] value (whose future `destroy`
168	/// semantics would risk freeing a tree it does not own). The slice-3.2
169	/// page-fault handler and slice-3.3's `VMCTL_PT_MAP` both go through here.
170	///
171	/// All table access is via HHDM; the target AS need not be the active one.
172	pub fn map_page_in(ttbr0_pa: u64, va: u64, pa: u64, prot: Prot) -> Result<(), MapError> {
173	    check_va(va)?;
174	    if pa & (FRAME_SIZE as u64 - 1) != 0 {
175	        return Err(MapError::Misaligned);
176	    }
177	
178	    let l1 = ensure_next_table(ttbr0_pa, pte_index(va, 0))?;
179	    let l2 = ensure_next_table(l1, pte_index(va, 1))?;
180	    let l3 = ensure_next_table(l2, pte_index(va, 2))?;
181	    let l3_table = table_mut(l3);
182	    let idx = pte_index(va, 3);
183	    if l3_table[idx] & PTE_VALID != 0 {
184	        return Err(MapError::AlreadyMapped);
185	    }
186	    l3_table[idx] = make_page_desc(pa, prot_attrs(prot));
187	    Ok(())
188	}
189	
190	/// Clear the leaf PTE at `va` in the page-table tree rooted at `ttbr0_pa`,
191	/// returning `Some(pa)` of the page that was mapped or `None` if `va` had no
192	/// leaf PTE.
193	///
194	/// This is the body of [`AddrSpace::unmap_page`], exposed as a free function
195	/// for the same reason as [`map_page_in`]: slice-3.3's `VMCTL_PT_UNMAP` clears
196	/// a PTE in a proc's *live* tree given only the `ttbr0_pa` from its
197	/// [`Proc`](crate::proc::Proc) slot. Intermediate L1/L2/L3 tables are left in
198	/// place (lazy pruning happens at [`AddrSpace::destroy`]); the freed PA is the
199	/// caller's to `free_frame` if appropriate.
200	pub fn unmap_page_in(ttbr0_pa: u64, va: u64) -> Option<u64> {
201	    check_va(va).ok()?;
202	    let l1 = next_table(ttbr0_pa, pte_index(va, 0))?;
203	    let l2 = next_table(l1, pte_index(va, 1))?;
204	    let l3 = next_table(l2, pte_index(va, 2))?;
205	    let l3_table = table_mut(l3);
206	    let idx = pte_index(va, 3);
207	    let pte = l3_table[idx];
208	    if pte & PTE_VALID == 0 {
209	        return None;
210	    }
211	    l3_table[idx] = 0;
212	    Some(pte & PA_MASK)
213	}
214	
215	/// Mask selecting the PA bits of a descriptor (47:12).
216	const PA_MASK: u64 = 0x0000_FFFF_FFFF_F000;
217	
218	/// One 48-bit user VA past the last legal address: `1 << 48`.
219	const USER_VA_TOP: u64 = 1 << 48;
220	
221	fn check_va(va: u64) -> Result<(), MapError> {
222	    if va & (FRAME_SIZE as u64 - 1) != 0 {
223	        return Err(MapError::Misaligned);
224	    }
225	    if va >= USER_VA_TOP {
226	        return Err(MapError::OutOfRange);
227	    }
228	    Ok(())
229	}
230	
231	fn pte_index(va: u64, level: u32) -> usize {
232	    let shift = PAGE_SHIFT + 9 * (3 - level);
233	    ((va >> shift) & 0x1FF) as usize
234	}
235	
236	const fn make_table_desc(next_table_pa: u64) -> u64 {
237	    (next_table_pa & PA_MASK) | PTE_VALID | PTE_TABLE
238	}
239	
240	const fn make_page_desc(pa: u64, attrs: u64) -> u64 {
241	    // At L3, both PTE_VALID and PTE_TABLE bits must be set to distinguish a
242	    // page descriptor from an invalid entry. `mmu::make_page_desc` documents
243	    // this; we mirror the same encoding.
244	    (pa & PA_MASK) | PTE_VALID | PTE_TABLE | attrs
245	}
246	
247	/// Borrow the 512-entry table at `table_pa` via HHDM for read.
248	fn table_ref(table_pa: u64) -> &'static [u64; PTES_PER_LEVEL] {
249	    // SAFETY: `table_pa` came from `alloc_frame`, so it is HHDM-mapped and
250	    // 4 KiB-aligned. Single-threaded boot — no concurrent writer.
251	    unsafe { &*(phys_to_hhdm(table_pa) as *const [u64; PTES_PER_LEVEL]) }
252	}
253	
254	/// Borrow the 512-entry table at `table_pa` via HHDM for mutation.
255	fn table_mut(table_pa: u64) -> &'static mut [u64; PTES_PER_LEVEL] {
256	    // SAFETY: `table_pa` came from `alloc_frame`, so it is HHDM-mapped and
257	    // 4 KiB-aligned. Single-threaded boot — no concurrent reader/writer.
258	    unsafe { &mut *(phys_to_hhdm(table_pa) as *mut [u64; PTES_PER_LEVEL]) }
259	}
260	
261	/// Return the PA of the child table at `parent[idx]`, or `None` if the slot
262	/// is empty or holds a non-table descriptor.
263	fn next_table(parent_pa: u64, idx: usize) -> Option<u64> {
264	    let desc = table_ref(parent_pa)[idx];
265	    if desc & PTE_VALID == 0 {
266	        return None;
267	    }
268	    // At L0/L1/L2, a table descriptor has PTE_TABLE=1; a valid entry with
269	    // PTE_TABLE=0 is a *block* descriptor (2 MiB / 1 GiB block) and must
270	    // NOT be followed as a sub-table. Slice 3.1a only ever writes table
271	    // descriptors via `ensure_next_table`, so this branch never fires
272	    // today — the check is future-proofing for any later slice that maps
273	    // a block (large-page support, identity ranges, etc.). (L3 page
274	    // descriptors also have PTE_TABLE=1, but we never call `next_table`
275	    // at L3.)
276	    if desc & PTE_TABLE == 0 {
277	        return None;
278	    }
279	    Some(desc & PA_MASK)
280	}
281	
282	/// Return the PA of the child table at `parent[idx]`, allocating and
283	/// linking it if absent.
284	fn ensure_next_table(parent_pa: u64, idx: usize) -> Result<u64, MapError> {
285	    let parent = table_mut(parent_pa);
286	    let desc = parent[idx];
287	    if desc & PTE_VALID != 0 {
288	        return Ok(desc & PA_MASK);
289	    }
290	    let child = alloc_frame().ok_or(MapError::OutOfMemory)?;
291	    parent[idx] = make_table_desc(child.addr());
292	    Ok(child.addr())
293	}
294	
295	/// Recursively free every intermediate table under `table_pa` at the given
296	/// `level` (0 = L0 root, 3 = L3 leaves). Page descriptors at L3 are left
297	/// alone (caller owns leaf frames); the table itself at L3 is freed by
298	/// the L2 recursion call. The L0 root is freed by [`AddrSpace::destroy`].
299	fn free_subtree(table_pa: u64, level: u32) {
300	    if level >= 3 {
301	        // L3 contains page descriptors, not table descriptors — nothing to
302	        // recurse into. The L3 frame itself was already linked at L2 and
303	        // will be freed by the L2 caller.
304	        return;
305	    }
306	    // Snapshot the entries into a local so the HHDM borrow of `table_pa`
307	    // ends before the recursive call (which takes fresh borrows of sibling
308	    // tables — overlapping `&` is fine for shared reads, but copying makes
309	    // the intent unambiguous).
310	    let entries: [u64; PTES_PER_LEVEL] = *table_ref(table_pa);
311	    for desc in entries.iter() {
312	        if *desc & PTE_VALID == 0 {
313	            continue;
314	        }
315	        let child_pa = *desc & PA_MASK;
316	        // Recurse to free grandchildren first, then free this child table.
317	        free_subtree(child_pa, level + 1);
318	        free_frame(Frame::from_addr(child_pa));
319	    }
320	}
321

