    let mut m = Message {
        m_source: 0,
        m_type: SYS_EXIT,
        payload: [0u8; 96],
    };
    wr_i32(&mut m, 0, target_e);
    let _ = ipc_sendrec(system, &mut m);
}

/// `SYS_ENDKSIG` — acknowledge `target_e`'s signals as handled.
#[cfg_attr(test, allow(dead_code))]
fn sys_endksig(system: Endpoint, target_e: Endpoint) {
    let mut m = Message {
        m_source: 0,
        m_type: SYS_ENDKSIG,
        payload: [0u8; 96],
    };
    wr_i32(&mut m, 0, target_e);
    let _ = ipc_sendrec(system, &mut m);
}

